    INSERT INTO CMN_FILE_DNLD_MGMT_MST /**cmn.filedown.insertCmnFileDnldMgmtMst */ 
	(
		     MENU_ID
		   , FILE_DN_DT
		   , USR_ID
		   , FILE_NM
		   , IP_INFO
		   , DUTY_NM
		   , FILE_ROUT
		   , FILE_SIZE
		   , DWNLD_RSN
		   , DATA_CNT
	) 
	VALUES 
	( 
		  nvl(#{menuId},'*')
		 ,sysdate
		 ,#{SESSION_USER_ID }
		 ,#{FILE_NM  }
		 ,#{IP_INFO  }
		 ,#{DUTY_NM  }
		 ,#{FILE_ROUT  }
		 ,#{FILE_SIZE  }
		 ,#{DWNLD_RSN }
		 ,#{DATA_CNT  }
	)

mapper.select:
SELECT /* cmn.filedown.selectExcelList */ EXCEL_DOWN_SEQ_NUM , FILE_NM /*, FILE_PATH*/ , REGST_ID , TO_CHAR(REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM FROM MSP_BOND_EXCEL_MGMT WHERE 1 = 1 AND REGST_ID = #{loginId}
AND (TO_CHAR(REGST_DTTM, 'YYYYMMDD') >= #{searchStartDt} AND TO_CHAR(REGST_DTTM, 'YYYYMMDD') <= #{searchEndDt})
ORDER BY REGST_DTTM DESC
